INSERT INTO `movie` (`title`, `original_title`, `cover`, `director`, `actors`, `genre`, `region`, `language`, `release_date`, `duration`, `summary`, `rating`, `rating_count`, `status`) VALUES
                                                                                                                                                                                             ('肖申克的救赎', 'The Shawshank Redemption', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p480747492.jpg', '弗兰克·德拉邦特', '蒂姆·罗宾斯,摩根·弗里曼', '剧情,犯罪', '美国', '英语', '1994-09-10', 142, '一场谋杀案使银行家安迪蒙冤入狱，谋杀妻子及其情人的罪名将他送进了肖申克监狱。在十九年的牢狱生涯中，他用智慧和希望完成了自我救赎。', 9.7, 2800000, 1),
                                                                                                                                                                                             ('霸王别姬', 'Farewell My Concubine', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2561716440.jpg', '陈凯歌', '张国荣,张丰毅,巩俐', '剧情,爱情,同性', '中国', '汉语普通话', '1993-01-01', 171, '段小楼与程蝶衣是一对打小一起长大的师兄弟，两人一个演生，一个饰旦，一向配合天衣无缝，尤其一出《霸王别姬》，誉满京城。', 9.6, 2100000, 1),
                                                                                                                                                                                             ('阿甘正传', 'Forrest Gump', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2372307693.jpg', '罗伯特·泽米吉斯', '汤姆·汉克斯,罗宾·怀特', '剧情,爱情', '美国', '英语', '1994-06-23', 142, '阿甘是个智商只有75的低能儿，但他的人生却像一盒巧克力，你永远不知道下一颗是什么味道。', 9.5, 2300000, 1),
                                                                                                                                                                                             ('泰坦尼克号', 'Titanic', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p457760035.jpg', '詹姆斯·卡梅隆', '莱昂纳多·迪卡普里奥,凯特·温丝莱特', '剧情,爱情,灾难', '美国', '英语', '1997-12-19', 194, '1912年4月10日，号称"世界工业史上的奇迹"的豪华客轮泰坦尼克号开始了自己的处女航，从英国的南安普顿出发驶往美国纽约。', 9.5, 2200000, 1),
                                                                                                                                                                                             ('千与千寻', '千と千尋の神隠し', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2557573348.jpg', '宫崎骏', '柊瑠美,入野自由', '动画,奇幻,冒险', '日本', '日语', '2001-07-20', 125, '千寻和爸爸妈妈一同驱车前往新家，在郊外的小路上不慎进入了神秘的隧道，来到了一个诡异世界。', 9.4, 2400000, 1),
                                                                                                                                                                                             ('美丽人生', 'La vita è bella', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2578474613.jpg', '罗伯托·贝尼尼', '罗伯托·贝尼尼,尼可莱塔·布拉斯基', '剧情,喜剧,爱情', '意大利', '意大利语', '1997-12-20', 116, '犹太青年圭多邂逅了美丽的女教师多拉，他彬彬有礼地向多拉鞠躬："早安！公主！"。', 9.5, 1400000, 1),
                                                                                                                                                                                             ('星际穿越', 'Interstellar', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2614988097.jpg', '克里斯托弗·诺兰', '马修·麦康纳,安妮·海瑟薇', '剧情,科幻,冒险', '美国', '英语', '2014-11-07', 169, '近未来的地球黄沙遍野，小麦、秋葵等基础农作物相继因枯萎病灭绝，人类不再像从前那样仰望星空，放纵想象力。', 9.4, 2100000, 1),
                                                                                                                                                                                             ('盗梦空间', 'Inception', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p513344864.jpg', '克里斯托弗·诺兰', '莱昂纳多·迪卡普里奥,约瑟夫·高登-莱维特', '剧情,科幻,悬疑', '美国', '英语', '2010-09-01', 148, '道姆·柯布与同事阿瑟和纳什在一次针对日本能源大亨齐藤的盗梦行动中失败，反被齐藤利用。', 9.4, 2300000, 1),
                                                                                                                                                                                             ('楚门的世界', 'The Truman Show', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p479682972.jpg', '彼得·威尔', '金·凯瑞,劳拉·琳妮', '剧情,科幻', '美国', '英语', '1998-06-05', 103, '楚门是一个标准的中产阶级，他生活在桃源岛，一个风景如画的小城。但他不知道的是，他的一举一动都被全球直播。', 9.4, 1800000, 1),
                                                                                                                                                                                             ('三傻大闹宝莱坞', '3 Idiots', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p579729551.jpg', '拉吉库马尔·希拉尼', '阿米尔·汗,卡琳娜·卡普尔', '剧情,喜剧,爱情', '印度', '印地语', '2009-12-25', 170, '法兰、拉杜与兰乔是皇家工程学院的学生，三人共居一室，结为好友。', 9.2, 1900000, 1),
                                                                                                                                                                                             ('机器人总动员', 'WALL·E', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p1461851991.jpg', '安德鲁·斯坦顿', '本·贝尔特,艾丽莎·奈特', '科幻,动画,冒险', '美国', '英语', '2008-06-27', 98, '公元2805年，人类文明高度发展，却因污染和生活垃圾大量增加使得地球不再适于人类居住。', 9.3, 1400000, 1),
                                                                                                                                                                                             ('放牛班的春天', 'Les choristes', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p1910824951.jpg', '克里斯托夫·巴拉蒂', '让-巴蒂斯特·莫尼耶,热拉尔·朱尼奥', '剧情,音乐', '法国', '法语', '2004-03-17', 97, '1949年的法国乡村，音乐家克莱门特到了一间外号叫"塘低"的男子寄宿学校当助理教师。', 9.3, 1300000, 1),
                                                                                                                                                                                             ('大话西游之大圣娶亲', '西游记大结局之仙履奇缘', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2455050536.jpg', '刘镇伟', '周星驰,朱茵', '喜剧,爱情,奇幻', '中国', '粤语', '1995-02-04', 95, '至尊宝被月光宝盒带回到五百年前，遇见紫霞仙子，被对方打上烙印成为对方的人，并发觉自己已变成孙悟空。', 9.2, 1700000, 1),
                                                                                                                                                                                             ('熔炉', '도가니', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p1363250216.jpg', '黄东赫', '孔刘,郑有美', '剧情', '韩国', '韩语', '2011-09-22', 125, '来自首尔的哑语美术老师仁浩来到雾津，应聘慈爱聋哑人学校。天降大雾，他意外撞车，维修时结识了人权组织成员柔珍。', 9.3, 1100000, 1),
                                                                                                                                                                                             ('教父', 'The Godfather', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p616779739.jpg', '弗朗西斯·福特·科波拉', '马龙·白兰度,阿尔·帕西诺', '剧情,犯罪', '美国', '英语', '1972-03-24', 175, '40年代的美国，"教父"维托·唐·柯里昂是黑手党柯里昂家族的首领，带领家族从事非法的勾当。', 9.3, 1200000, 1),
                                                                                                                                                                                             ('无间道', '無間道', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2564556863.jpg', '刘伟强,麦兆辉', '刘德华,梁朝伟,黄秋生', '剧情,犯罪,悬疑', '中国', '粤语', '2002-12-12', 101, '1991年，香港黑帮三合会会员刘健明听从老大韩琛的指示，加入警察部队成为黑帮卧底。', 9.3, 1500000, 1),
                                                                                                                                                                                             ('疯狂动物城', 'Zootopia', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2614500649.jpg', '拜伦·霍华德,瑞奇·摩尔', '金妮弗·古德温,杰森·贝特曼', '喜剧,动画,冒险', '美国', '英语', '2016-03-04', 109, '故事发生在一个所有哺乳类动物和谐共存的美好世界中，兔子朱迪从小就梦想着能够成为一名惩恶扬善的刑警。', 9.2, 1900000, 1),
                                                                                                                                                                                             ('当幸福来敲门', 'The Pursuit of Happyness', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p2614359276.jpg', '加布里尔·穆奇诺', '威尔·史密斯,贾登·史密斯', '剧情,传记,家庭', '美国', '英语', '2006-12-15', 117, '克里斯·加纳用尽全部积蓄买下了高科技治疗仪，到处向医院推销，可是价格高昂，接受的人不多。', 9.2, 1600000, 1),
                                                                                                                                                                                             ('怦然心动', 'Flipped', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p501177648.jpg', '罗伯·莱纳', '玛德琳·卡罗尔,卡兰·麦克奥利菲', '剧情,喜剧,爱情', '美国', '英语', '2010-07-26', 90, '布莱斯全家搬到小镇，邻家女孩朱丽前来帮忙。她对他一见钟情，心愿是获得他的吻。', 9.1, 1400000, 1),
                                                                                                                                                                                             ('触不可及', 'Intouchables', 'https://img.doubanio.com/view/photo/s_ratio_poster/public/p1454261925.jpg', '奥利维埃·纳卡什,埃里克·托莱达诺', '弗朗索瓦·克鲁塞,奥玛·希', '剧情,喜剧', '法国', '法语', '2011-11-02', 112, '因为一次跳伞事故，白人富翁菲利普瘫痪在床，欲招聘一名全职陪护。', 9.3, 1200000, 1);